import { Helmet } from "react-helmet-async";
import { Link } from "wouter";
import { ArrowRight, Calculator, HeartPulse, Landmark, Sigma } from "lucide-react";
import SEOHead from "@/components/SEOHead";
import { getMeta } from "@/data/calcMeta";
import { calculatorRoutes, SITE_URL } from "@/data/siteRoutes";

type CategoryKey = "Financial" | "Health" | "Math";

const CATEGORY_CONFIG: Record<CategoryKey, {
  path: string;
  title: string;
  h1: string;
  description: string;
  intro: string;
  keywords: string;
  Icon: typeof Calculator;
  accent: string;
}> = {
  Financial: {
    path: "/financial-calculators",
    title: "Free Financial Calculators Online",
    h1: "Free Financial Calculators Online",
    description: "Explore free financial calculators online for loans, mortgages, savings, investing, taxes, retirement, debt payoff, budgeting, and more.",
    intro: "Use CalcHive's financial calculator hub to compare payments, estimate interest, plan retirement, calculate taxes, review debt payoff scenarios, and make everyday money decisions with fast no-signup tools.",
    keywords: "free financial calculators online, finance calculators, loan calculators, mortgage calculators, retirement calculators, tax calculators, investment calculators",
    Icon: Landmark,
    accent: "text-sky-600 bg-sky-50 dark:text-sky-400 dark:bg-sky-950/50",
  },
  Health: {
    path: "/health-calculators",
    title: "Free Health Calculators Online",
    h1: "Free Health Calculators Online",
    description: "Explore free health calculators online for BMI, calories, body fat, BMR, pregnancy, macros, protein, TDEE, heart rate, and fitness planning.",
    intro: "Use CalcHive's health calculator hub to estimate body metrics, nutrition targets, pregnancy dates, fitness zones, and wellness numbers with practical tools that work on mobile and desktop.",
    keywords: "free health calculators online, BMI calculator, calorie calculator, body fat calculator, BMR calculator, macro calculator, pregnancy calculator",
    Icon: HeartPulse,
    accent: "text-teal-600 bg-teal-50 dark:text-teal-400 dark:bg-teal-950/50",
  },
  Math: {
    path: "/math-calculators",
    title: "Free Math Calculators Online",
    h1: "Free Math Calculators Online",
    description: "Explore free math calculators online for percentages, fractions, algebra, geometry, statistics, probability, matrices, exponents, roots, and more.",
    intro: "Use CalcHive's math calculator hub for schoolwork, formulas, conversions, statistics, geometry, algebra, number theory, and quick arithmetic checks with clear free online tools.",
    keywords: "free math calculators online, math calculator, algebra calculator, geometry calculator, statistics calculator, percentage calculator, fraction calculator",
    Icon: Sigma,
    accent: "text-violet-600 bg-violet-50 dark:text-violet-400 dark:bg-violet-950/50",
  },
};

function toolsForCategory(category: CategoryKey) {
  return calculatorRoutes
    .filter((route) => route.category === category)
    .map((route) => {
      const meta = getMeta(route.path);
      return {
        href: route.path,
        title: meta?.h1?.replace(/\s[--]\s.*$/, "") ?? route.path.replace(/^\//, "").replace(/-/g, " "),
        description: meta?.description ?? `Use this free online ${category.toLowerCase()} calculator for instant results on CalcHive.`,
      };
    });
}

function CategorySchema({ category, tools }: { category: CategoryKey; tools: ReturnType<typeof toolsForCategory> }) {
  const config = CATEGORY_CONFIG[category];
  const itemListSchema = {
    "@context": "https://schema.org",
    "@type": "ItemList",
    "name": config.h1,
    "description": config.description,
    "numberOfItems": tools.length,
    "itemListElement": tools.map((tool, index) => ({
      "@type": "ListItem",
      "position": index + 1,
      "name": tool.title,
      "description": tool.description,
      "url": `${SITE_URL}${tool.href}`,
    })),
  };

  return (
    <Helmet>
      <script type="application/ld+json">{JSON.stringify(itemListSchema)}</script>
    </Helmet>
  );
}

export default function CategoryCalculatorsPage({ category }: { category: CategoryKey }) {
  const config = CATEGORY_CONFIG[category];
  const tools = toolsForCategory(category);
  const Icon = config.Icon;

  return (
    <>
      <SEOHead
        title={config.title}
        description={config.description}
        canonical={config.path}
        keywords={config.keywords}
        category="company"
        breadcrumbName={config.h1}
        schemaType="WebApplication"
      />
      <CategorySchema category={category} tools={tools} />
      <main className="min-h-screen bg-background">
        <section className="mx-auto w-full max-w-6xl px-4 py-10 sm:px-6 lg:px-8">
          <div className="mb-8 max-w-3xl">
            <div className={`mb-4 flex h-12 w-12 items-center justify-center rounded-2xl ${config.accent}`}>
              <Icon className="h-6 w-6" />
            </div>
            <p className="mb-2 text-xs font-bold uppercase tracking-[0.18em] text-muted-foreground">
              {tools.length} calculators
            </p>
            <h1 className="text-3xl font-black tracking-tight text-foreground sm:text-4xl">
              {config.h1}
            </h1>
            <p className="mt-4 text-base leading-relaxed text-muted-foreground sm:text-lg">
              {config.intro}
            </p>
          </div>

          <div className="grid grid-cols-2 gap-2.5 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5">
            {tools.map((tool) => (
              <Link
                key={tool.href}
                href={tool.href}
                className="group relative flex min-w-0 flex-col rounded-xl border border-border bg-card p-3 transition-all duration-150 hover:border-primary/40 hover:shadow-md active:scale-[0.98]"
              >
                <div className="mb-2 flex items-center gap-2">
                  <div className={`flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-lg ${config.accent}`}>
                    <Calculator className="h-4 w-4" />
                  </div>
                  <span className="truncate text-[9px] font-bold uppercase tracking-wide text-muted-foreground">
                    {category}
                  </span>
                </div>
                <h2 className="mb-1 line-clamp-2 text-xs font-bold leading-snug text-foreground transition-colors group-hover:text-primary">
                  {tool.title}
                </h2>
                <p className="line-clamp-3 text-[10px] leading-relaxed text-muted-foreground">
                  {tool.description}
                </p>
                <div className="mt-auto flex justify-end pt-3">
                  <ArrowRight className="h-3.5 w-3.5 text-muted-foreground transition-all group-hover:translate-x-0.5 group-hover:text-primary" />
                </div>
              </Link>
            ))}
          </div>

          <section className="mt-10 rounded-2xl border border-border bg-card p-5 sm:p-6">
            <h2 className="text-xl font-bold text-foreground">
              Why Use CalcHive {category} Calculators?
            </h2>
            <p className="mt-3 text-sm leading-relaxed text-muted-foreground">
              These free {category.toLowerCase()} calculators online are built for quick answers, clear descriptions, and practical everyday use. Every calculator opens in your browser, works on mobile and desktop, and requires no account or signup.
            </p>
          </section>
        </section>
      </main>
    </>
  );
}


